  "questionProse": [
    "¿Cuál es el tamaño en píxeles del texto del enlace `<a>` en el siguiente HTML?"
  ],
  "explanationProse": [
    "El `font-size` para `<a>` se calcula como 5px: 40px (body) * 50% (nav) = 20px, luego 20px * 25% = 5px."
  ]
